```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Calculate the actual number of bytes to preview (minimum of requested and available)
    size_t preview_size = std::min(bytes_to_preview, buffer.size());

    // Create a vector with the appropriate size
    std::vector<uint8_t> preview_data(preview_size);

    // Use the copy method to copy data without advancing the read pointer
    buffer.copy(preview_data.data(), preview_size);

    return preview_data;
}
```

