std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to hold all the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor instance
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Calculate total size needed
    std::size_t total_size = 0;
    for (const auto& chunk : chunks) {
        total_size += chunk.size();
    }

    // Pre-allocate buffer to avoid reallocations
    buffer.resize(total_size);

    // Write each chunk with space checking
    std::size_t total_written = 0;
    for (const auto& chunk : chunks) {
        // Check available space before writing
        if (adaptor.free() < chunk.size()) {
            // Handle error - not enough space
            return total_written;
        }

        // Write the chunk
        adaptor.write(chunk.data(), chunk.size());
        total_written += chunk.size();
    }

    // Return total size written using size() function
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(buffer);

    std::vector<uint8_t> result;

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        // Determine how much to read in this chunk
        std::size_t read_size = std::min(chunk_size, adaptor.size());

        // Create temporary buffer for this chunk
        std::vector<uint8_t> chunk(read_size);

        // Read the data
