    hexi::pmc::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);
    hexi::pmc::binary_stream<decltype(adaptor)> stream(adaptor);

    // Convert message_id to big-endian and write
    auto message_id_be = hexi::endian::native_to_big(packet.message_id);
