Based on the reference materials and detailed specifications, here's the complete implementation:

```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) {
        if constexpr (requires { adaptor.write(0); }) {
            // Serialization (writing)
            adaptor.write(&sensor_id, sizeof(sensor_id));

            for (auto& temp : temperatures) {
                float converted = hexi::endian::conditional_reverse(
                    temp, std::endian::native, std::endian::little
                );
                adaptor.write(&converted, sizeof(converted));
            }

            double converted_pressure = hexi::endian::conditional_reverse(
                pressure, std::endian::native, std::endian::little
            );
            adaptor.write(&converted_pressure, sizeof(converted_pressure));
        } else {
            // Deserialization (reading)
            adaptor.read(&sensor_id, sizeof(sensor_id));

            // Read temperatures count first (assuming it's stored)
            uint32_t count;
            adaptor.read(&count, sizeof(count));
            temperatures.resize(count);

            for (auto& temp : temperatures) {
                float read_value;
                adaptor.read(&read_value, sizeof(read_value));
                hexi::endian::little_to_native_inplace(read_value);
                temp = read_value;
            }

            double read_pressure;
            adaptor.read(&read_pressure, sizeof(read_pressure));
            hexi::endian::little_to_native_inplace(read_pressure);
            pressure = read_pressure;
        }
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream.serialise(data);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData result;
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());
    hexi::binary_stream stream(adaptor);

    stream.deserialise(result);
    return result;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());
    hexi::binary_stream stream(adaptor);

    // Extract sensor name using view
    info.sensor_name = stream.view();

    // Check bounds before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(&info.sensor_id, sizeof(uint32_t));

    // Skip remaining data
    size_t remaining_bytes = buffer.size() - stream.total_read();
    if (remaining_bytes > 0) {
        stream.skip(remaining_bytes);
    }

    return info;
}
